+    /// Regression test for frankensqlite#69: DROP INDEX + CREATE INDEX and
+    /// DROP TABLE + ALTER TABLE RENAME must return old root pages to the
+    /// freelist. Without the fix in `execute_drop` → `free_btree_pages`,
+    /// the old root pages become orphaned ("Page N: never used").
+    #[cfg(unix)]
+    #[test]
+    fn test_drop_index_and_table_returns_pages_to_freelist() {
+        let _serial = super::fsqlite_core_test_serializer();
+        let cx = Cx::new();
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("drop_freelist_repro.db");
+        let db_str = db_path.to_string_lossy().into_owned();
+
+        let pager = Arc::new(
+            SimplePager::open_with_cx(&cx, UnixVfs::new(), &db_path, PageSize::DEFAULT)
+                .expect("open unix pager"),
+        );
+        let conn = Connection::open_with_env_and_pager(
+            db_str.clone(),
+            ConnectionEnv::default(),
+            PagerBackend::Unix(pager),
+        )
+        .expect("open connection");
+
+        conn.execute("PRAGMA journal_mode = WAL;").unwrap();
+        conn.execute("PRAGMA busy_timeout = 5000;").unwrap();
+
+        // Create a beads-like schema with a partial index and events table.
+        conn.execute(
+            "CREATE TABLE issues (
+                id TEXT PRIMARY KEY,
+                content_hash TEXT,
+                title TEXT NOT NULL,
+                status TEXT NOT NULL,
+                priority INTEGER NOT NULL,
+                issue_type TEXT NOT NULL,
+                created_at TEXT NOT NULL,
+                updated_at TEXT NOT NULL,
+                ephemeral INTEGER NOT NULL DEFAULT 0,
+                pinned INTEGER NOT NULL DEFAULT 0,
+                is_template INTEGER NOT NULL DEFAULT 0
+            );",
+        )
+        .unwrap();
+        conn.execute(
+            "CREATE INDEX idx_issues_ready
+             ON issues(status, priority, created_at)
+             WHERE status = 'open'
+               AND ephemeral = 0
+               AND pinned = 0
+               AND is_template = 0;",
+        )
+        .unwrap();
+        conn.execute(
+            "CREATE TABLE events (
+                id INTEGER PRIMARY KEY AUTOINCREMENT,
+                issue_id TEXT NOT NULL,
+                event_type TEXT NOT NULL,
+                actor TEXT NOT NULL DEFAULT '',
+                old_value TEXT,
+                new_value TEXT,
+                comment TEXT,
+                created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP
+            );",
+        )
+        .unwrap();
+        conn.execute("CREATE INDEX idx_events_issue ON events(issue_id);")
+            .unwrap();
+        conn.execute("CREATE INDEX idx_events_type ON events(event_type);")
+            .unwrap();
+        conn.execute(
+            "CREATE INDEX idx_events_created_at ON events(created_at);",
+        )
+        .unwrap();
+        conn.execute(
+            "CREATE INDEX idx_events_actor ON events(actor) WHERE actor != '';",
+        )
+        .unwrap();
+        conn.execute(
+            "CREATE TABLE metadata(key TEXT NOT NULL, value TEXT NOT NULL);",
+        )
+        .unwrap();
+        conn.execute("CREATE INDEX idx_metadata_key ON metadata(key);")
+            .unwrap();
+
+        // Seed some data so pages are actually allocated.
+        conn.execute("BEGIN;").unwrap();
+        for i in 0..20 {
+            conn.execute(&format!(
+                "INSERT INTO issues(id, content_hash, title, status, priority, \
+                 issue_type, created_at, updated_at) VALUES \
+                 ('bd-{i:03}', 'hash-{i}', 'Issue {i}', 'open', {}, 'task', \
+                  '2026-04-13T00:00:00Z', '2026-04-13T00:00:00Z');",
+                i % 5
+            ))
+            .unwrap();
+            conn.execute(&format!(
+                "INSERT INTO events(issue_id, event_type, actor, created_at) \
+                 VALUES ('bd-{i:03}', 'created', 'tester', '2026-04-13T00:00:00Z');",
+            ))
+            .unwrap();
+        }
+        conn.execute("COMMIT;").unwrap();
+
+        // Baseline integrity check.
+        conn.close().unwrap();
+        let sqlite = rusqlite::Connection::open(&db_path).unwrap();
+        let baseline: String = sqlite
+            .query_row("PRAGMA integrity_check;", [], |row| row.get(0))
+            .unwrap();
+        assert_eq!(baseline, "ok", "baseline must be clean before DDL");
+        sqlite.close().unwrap();
+
+        // Reopen and run the DDL that was causing orphaned pages:
+        // 1. DROP INDEX + CREATE INDEX (ready-index recreation)
+        // 2. DROP TABLE + CREATE TABLE + RENAME (events v5 migration)
+        let pager2 = Arc::new(
+            SimplePager::open_with_cx(&cx, UnixVfs::new(), &db_path, PageSize::DEFAULT)
+                .expect("reopen unix pager"),
+        );
+        let conn2 = Connection::open_with_env_and_pager(
+            db_str.clone(),
+            ConnectionEnv::default(),
+            PagerBackend::Unix(pager2),
+        )
+        .expect("reopen connection");
+        conn2.execute("PRAGMA journal_mode = WAL;").unwrap();
+        conn2.execute("PRAGMA busy_timeout = 5000;").unwrap();
+
+        // Migration 1: ready-index recreation
+        conn2
+            .execute("DROP INDEX IF EXISTS idx_issues_ready;")
+            .unwrap();
+        conn2
+            .execute(
+                "CREATE INDEX idx_issues_ready
+                 ON issues(status, priority, created_at)
+                 WHERE status = 'open'
+                   AND ephemeral = 0
+                   AND pinned = 0
+                   AND is_template = 0;",
+            )
+            .unwrap();
+
+        // Migration 2: events table rebuild via rename pattern
+        conn2.execute("PRAGMA foreign_keys = OFF;").unwrap();
+        conn2.execute("BEGIN IMMEDIATE;").unwrap();
+        conn2
+            .execute("DROP TABLE IF EXISTS events_migrated;")
+            .unwrap();
+        conn2
+            .execute(
+                "CREATE TABLE events_migrated (
+                    id INTEGER PRIMARY KEY AUTOINCREMENT,
+                    issue_id TEXT NOT NULL,
+                    event_type TEXT NOT NULL,
+                    actor TEXT NOT NULL DEFAULT '',
+                    old_value TEXT,
+                    new_value TEXT,
+                    comment TEXT,
+                    created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP
+                );",
+            )
+            .unwrap();
+        conn2
+            .execute("INSERT INTO events_migrated SELECT * FROM events;")
+            .unwrap();
+        conn2.execute("DROP TABLE events;").unwrap();
+        conn2
+            .execute("ALTER TABLE events_migrated RENAME TO events;")
+            .unwrap();
+        conn2
+            .execute("CREATE INDEX IF NOT EXISTS idx_events_issue ON events(issue_id);")
+            .unwrap();
+        conn2
+            .execute("CREATE INDEX IF NOT EXISTS idx_events_type ON events(event_type);")
+            .unwrap();
+        conn2
+            .execute(
+                "CREATE INDEX IF NOT EXISTS idx_events_created_at ON events(created_at);",
+            )
+            .unwrap();
+        conn2
+            .execute(
+                "CREATE INDEX IF NOT EXISTS idx_events_actor ON events(actor) WHERE actor != '';",
+            )
+            .unwrap();
+        conn2.execute("COMMIT;").unwrap();
+        conn2.execute("PRAGMA foreign_keys = ON;").unwrap();
+
+        conn2.close().unwrap();
+
+        // Verify: stock SQLite integrity_check must be clean.
+        let sqlite2 = rusqlite::Connection::open(&db_path).unwrap();
+        let integrity: String = sqlite2
+            .query_row("PRAGMA integrity_check;", [], |row| row.get(0))
+            .unwrap();
+        assert_eq!(
+            integrity, "ok",
+            "DROP INDEX + CREATE INDEX and DROP TABLE + RENAME must not \
+             orphan pages (frankensqlite#69)"
+        );
+
+        // Also verify the freelist count increased (pages were returned).
+        let freelist: i64 = sqlite2
+            .query_row("PRAGMA freelist_count;", [], |row| row.get(0))
+            .unwrap();
+        assert!(
+            freelist > 0,
+            "freelist_count should be > 0 after dropping and recreating \
+             objects (old pages reclaimed), got {freelist}"
+        );
+    }
+
